            <div style="position:absolute;left:4px;bottom:26px;width:72px;height:2.5px;transform:rotate(-32deg);transform-origin:left center;background:linear-gradient(90deg, rgba(255,232,184,.7), transparent);filter:blur(.6px);pointer-events:none;"></div>
